$ErrorActionPreference = 'Stop'
$repoRoot = 'C:\PORTAL-VETNEB'
if (-not (Test-Path $repoRoot)) { throw "No existe el repositorio en $repoRoot" }
$files = @(
  @{
    Path = '.github/workflows/backend-ci.yml'
    Base64 = ''
  }
  @{
    Path = 'CHANGELOG.md'
    Base64 = ''
  }
  @{
    Path = 'drizzle/migrations/0014_report_access_tokens.sql'
    Base64 = ''
  }
  @{
    Path = 'drizzle/migrations/meta/0014_snapshot.json'
    Base64 = ''
  }
  @{
    Path = 'drizzle/migrations/meta/_journal.json'
    Base64 = ''
  }
  @{
    Path = 'drizzle/schema.ts'
    Base64 = ''
  }
  @{
    Path = 'package.json'
    Base64 = ''
  }
  @{
    Path = 'server/app.ts'
    Base64 = ''
  }
  @{
    Path = 'server/db-report-access.ts'
    Base64 = ''
  }
  @{
    Path = 'server/lib/report-access-token.ts'
    Base64 = ''
  }
  @{
    Path = 'server/middlewares/request-logger.ts'
    Base64 = ''
  }
  @{
    Path = 'server/routes/admin-report-access-tokens.routes.ts'
    Base64 = ''
  }
  @{
    Path = 'server/routes/public-report-access.routes.ts'
    Base64 = ''
  }
  @{
    Path = 'server/routes/report-access-tokens.routes.ts'
    Base64 = ''
  }
  @{
    Path = 'test/report-access-token.test.ts'
    Base64 = ''
  }
  @{
    Path = 'test/request-logger.test.ts'
    Base64 = ''
  }
)

foreach ($file in $files) {
  $targetPath = Join-Path $repoRoot ($file.Path -replace '/', '\')
  $targetDir = Split-Path -Parent $targetPath
  if (-not (Test-Path $targetDir)) {
    New-Item -ItemType Directory -Force -Path $targetDir | Out-Null
  }
  $bytes = [Convert]::FromBase64String($file.Base64)
  $content = [System.Text.Encoding]::UTF8.GetString($bytes)
  [System.IO.File]::WriteAllText($targetPath, $content, (New-Object System.Text.UTF8Encoding($false)))
  Write-Host "OK  $($file.Path)"
}

Write-Host ''
Write-Host 'PR5 report_access_tokens aplicado correctamente sobre C:\PORTAL-VETNEB'